package com.agrios.platform.workmanagement.application;
import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*; import com.agrios.platform.inventory.domain.*; import com.agrios.platform.operations.domain.*; import com.agrios.platform.tasks.domain.*; import java.time.Instant; import java.util.*; import org.junit.jupiter.api.Test;
class WorkManagementQueryServiceTest { @Test void emptyCalendarIsStable(){var tasks=mock(TaskRepository.class);var operations=mock(FarmOperationRepository.class);when(tasks.findByTenantIdAndDueAtBetweenOrderByDueAt(any(),any(),any())).thenReturn(List.of());when(operations.findByTenantIdAndOperationDateBetweenOrderByOperationDate(any(),any(),any())).thenReturn(List.of());var service=new WorkManagementQueryService(tasks,operations,mock(InventoryItemRepository.class),mock(InventoryLotRepository.class));assertTrue(service.calendar(UUID.randomUUID(),Instant.now(),Instant.now().plusSeconds(60)).isEmpty());}}
